3.47552728292131],[10.0831979358928,53.47549379731889],[10.08314179497457,53.47552165127809],[10.083161633302659,53.47554627259404],[10.083179324356271,53.47556822560713],[10.083190316447318,53.47557148792042],[10.083371063292857,53.47562511483863],[10.08337510174049,53.47562630974262],[10.083502443258789,53.4757288003767]]]}';
        $resultingGeoJson = '{"type":"Polygon","coordinates":[[[1122490.3573962983,7071484.285754054],[1122482.2362970402,7071490.40680759],[1122478.999109264,7071492.845304786],[1122475.2042036585,7071495.781567061],[1122471.5251732466,7071498.5058959145],[1122471.360964572,7071498.627772408],[1122469.9660731317,7071499.224038446],[1122463.02764217,7071505.135395698],[1122451.0108444085,7071515.071890943],[1122435.128717185,7071525.847386543],[1122434.268690556,7071526.4304593485],[1122410.0366806341,7071547.389219202],[1122421.1579644377,7071561.588730869],[1122441.4799638607,7071587.54543312],[1122456.3661907252,7071606.558539621],[1122430.3149269223,7071588.72595191],[1122402.707278053,7071568.131007109],[1122396.0806524877,7071563.187822573],[1122350.858337287,7071529.455500149],[1122335.8999894143,7071516.840991722],[1122325.8392592138,7071506.425138527],[1122316.3031768298,7071497.64565565],[1122300.8185980634,7071483.391426601],[1122293.7498677047,7071475.827006324],[1122290.965665827,7071472.846312364],[1122288.0672533428,7071469.744618191],[1122283.0888017584,7071464.416527989],[1122299.6096302131,7071442.753501105],[1122320.7897785942,7071414.985345006],[1122334.505386014,7071395.280075988],[1122332.6508171991,7071393.875809563],[1122332.830013415,7071393.636017209],[1122335.6712878277,7071389.863623659],[1122356.6622858304,7071362.0278163785],[1122359.7101755266,7071358.9416223075],[1122366.7414734326,7071366.0306309415],[1122363.7870400304,7071369.307077891],[1122340.8624427796,7071399.7128248485],[1122320.6475335688,7071426.528118282],[1122317.0646003806,7071431.280250348],[1122319.3874984237,7071433.704692957],[1122362.406354156,7071478.592353006],[1122388.8004967493,7071460.632449447],[1122400.3920099915,7071477.869576714],[1122411.4351000325,7071469.425922151],[1122428.9701568882,7071458.0419582715],[1122432.4341652468,7071454.964494912],[1122435.8556671,7071452.624101453],[1122437.2985384408,7071451.763145272],[1122445.9607397611,7071446.593966149]